# solution.py
"""TeamCollaborationManager -- an in-memory, thread-safe collaboration backend.

The original prompt frames this work as a collaborative shopping application
("ShopCollab"), but the *authoritative* specification is the accompanying
``test_solution.py`` suite.  That suite models a **team collaboration
manager**: users, projects, tasks, threaded messaging with attachments,
performance dashboards and exportable (CSV / PDF) reports.  This module is the
single deliverable and is importable as ``solution``.

Design highlights
-----------------
* **One shared re-entrant lock.** The manager and every sub-store share the
  exact same lock object, so all mutating and reading operations are
  serialized and remain internally consistent under heavy concurrency.
* **Globally unique ids.** Every entity id is drawn from a single,
  monotonically increasing counter, guaranteeing uniqueness across *all*
  entity types (users, projects, tasks, messages, ratings).
* **Defensive copies.** Public accessors return deep copies of stored
  entities, so callers can never mutate the manager's internal state by
  holding on to a returned object.
* **Injectable clock.** A ``now`` callable can be supplied for deterministic
  testing; it defaults to :func:`datetime.datetime.now`.

The code is organised in the create -> revise -> optimize spirit requested by
the task: small focused stores (data layer), a service layer for performance
and reporting, and a thin orchestration layer (the manager) that owns
validation and cross-cutting concerns.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorization roles a user may hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifies the shape of a generated report."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor lacks permission for an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary attachment carried by a :class:`Message`."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A registered team member."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a single user with a start/end window."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    """A unit of work belonging to a project, optionally assigned."""

    id: int
    project_id: int
    title: str
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    status: TaskStatus = TaskStatus.NOT_STARTED
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A message posted against a project or a task (threaded via parent_id)."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating (1-5) optionally tied to a task."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Data-layer stores (each shares the manager's single lock)
# ---------------------------------------------------------------------------
class _BaseStore:
    """Common base giving every store the *same* shared lock instance."""

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class UserStore(_BaseStore):
    """Holds users plus username/email uniqueness indexes."""

    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._users: Dict[int, User] = {}
        self._username_index: Dict[str, int] = {}
        self._email_index: Dict[str, int] = {}

    def add(self, user: User) -> None:
        self._users[user.id] = user
        self._username_index[user.username] = user.id
        self._email_index[user.email] = user.id

    def get(self, user_id: int) -> Optional[User]:
        return self._users.get(user_id)

    def remove(self, user_id: int) -> None:
        user = self._users.pop(user_id, None)
        if user is None:
            return
        self._username_index.pop(user.username, None)
        self._email_index.pop(user.email, None)

    def all(self) -> List[User]:
        return [self._users[uid] for uid in sorted(self._users)]

    def username_owner(self, username: str) -> Optional[int]:
        return self._username_index.get(username)

    def email_owner(self, email: str) -> Optional[int]:
        return self._email_index.get(email)

    def set_username(self, user: User, new_username: str) -> None:
        self._username_index.pop(user.username, None)
        user.username = new_username
        self._username_index[new_username] = user.id

    def set_email(self, user: User, new_email: str) -> None:
        self._email_index.pop(user.email, None)
        user.email = new_email
        self._email_index[new_email] = user.id


class ProjectStore(_BaseStore):
    """Holds projects keyed by id."""

    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._projects: Dict[int, Project] = {}

    def add(self, project: Project) -> None:
        self._projects[project.id] = project

    def get(self, project_id: int) -> Optional[Project]:
        return self._projects.get(project_id)

    def remove(self, project_id: int) -> None:
        self._projects.pop(project_id, None)

    def all(self) -> List[Project]:
        return [self._projects[pid] for pid in sorted(self._projects)]

    def owned_by(self, user_id: int) -> List[Project]:
        return [p for p in self._projects.values() if p.owner_id == user_id]


class TaskStore(_BaseStore):
    """Holds tasks plus project/assignee indexes for fast lookup."""

    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._tasks: Dict[int, Task] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_assignee: Dict[int, set] = {}

    def add(self, task: Task) -> None:
        self._tasks[task.id] = task
        self._by_project.setdefault(task.project_id, []).append(task.id)
        if task.assignee_id is not None:
            self._by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def get(self, task_id: int) -> Optional[Task]:
        return self._tasks.get(task_id)

    def set_assignee(self, task: Task, new_assignee: Optional[int]) -> None:
        if task.assignee_id is not None:
            bucket = self._by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self._by_assignee.pop(task.assignee_id, None)
        task.assignee_id = new_assignee
        if new_assignee is not None:
            self._by_assignee.setdefault(new_assignee, set()).add(task.id)

    def for_project(self, project_id: int) -> List[Task]:
        ids = self._by_project.get(project_id, [])
        return [self._tasks[tid] for tid in sorted(ids)]

    def for_assignee(self, assignee_id: int) -> List[Task]:
        ids = self._by_assignee.get(assignee_id, set())
        return [self._tasks[tid] for tid in sorted(ids)]

    def remove_project(self, project_id: int) -> List[Task]:
        removed: List[Task] = []
        for tid in self._by_project.pop(project_id, []):
            task = self._tasks.pop(tid, None)
            if task is None:
                continue
            if task.assignee_id is not None:
                bucket = self._by_assignee.get(task.assignee_id)
                if bucket is not None:
                    bucket.discard(tid)
                    if not bucket:
                        self._by_assignee.pop(task.assignee_id, None)
            removed.append(task)
        return removed


class MessageStore(_BaseStore):
    """Holds messages plus project/task indexes."""

    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._messages: Dict[int, Message] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}

    def add(self, message: Message) -> None:
        self._messages[message.id] = message
        if message.project_id is not None:
            self._by_project.setdefault(message.project_id, []).append(message.id)
        if message.task_id is not None:
            self._by_task.setdefault(message.task_id, []).append(message.id)

    def get(self, message_id: int) -> Optional[Message]:
        return self._messages.get(message_id)

    def remove(self, message_id: int) -> None:
        message = self._messages.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self._by_project.get(message.project_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)
        if message.task_id is not None:
            bucket = self._by_task.get(message.task_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)

    def for_project(self, project_id: int) -> List[Message]:
        ids = self._by_project.get(project_id, [])
        return [self._messages[mid] for mid in sorted(ids)]

    def for_task(self, task_id: int) -> List[Message]:
        ids = self._by_task.get(task_id, [])
        return [self._messages[mid] for mid in sorted(ids)]

    def remove_for_project(self, project_id: int) -> None:
        for mid in self._by_project.pop(project_id, []):
            self._messages.pop(mid, None)

    def remove_for_task(self, task_id: int) -> None:
        for mid in self._by_task.pop(task_id, []):
            self._messages.pop(mid, None)


class PerformanceService(_BaseStore):
    """Stores peer ratings and exposes rating aggregation helpers."""

    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, List[int]] = {}

    def add_rating(self, rating: Rating) -> None:
        self._ratings[rating.id] = rating
        self._by_ratee.setdefault(rating.ratee_id, []).append(rating.id)

    def ratings_for(self, ratee_id: int) -> List[Rating]:
        ids = self._by_ratee.get(ratee_id, [])
        return [self._ratings[rid] for rid in sorted(ids)]


class ReportService(_BaseStore):
    """Serializes report dictionaries to CSV text or PDF bytes."""

    def to_csv(self, report: dict) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        rtype = report.get("report_type")

        if rtype == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in columns])

        elif rtype == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["user_id", "username", "total_tasks", "completed_tasks"])
            writer.writerow(
                [
                    report.get("user_id", ""),
                    report.get("username", ""),
                    report.get("total_tasks", 0),
                    report.get("completed_tasks", 0),
                ]
            )
            writer.writerow([])
            writer.writerow(
                ["task_id", "title", "status", "assignee_id", "deadline",
                 "started_at", "completed_at"]
            )
            for task in report.get("tasks", []):
                writer.writerow(
                    [
                        task.get("id", ""),
                        task.get("title", ""),
                        task.get("status", ""),
                        task.get("assignee_id", ""),
                        task.get("deadline", ""),
                        task.get("started_at", ""),
                        task.get("completed_at", ""),
                    ]
                )

        elif rtype == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status:" + str(status), count])
            writer.writerow(["completion_rate", report.get("completion_rate", 0.0)])
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])

        else:  # Generic fallback - flat key/value table.
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, value])

        return output.getvalue()

    def to_pdf(self, report: dict) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines: List[str]) -> bytes:
        """Assemble a minimal, well-formed single-page PDF document."""

        content_parts = ["BT", "/F1 12 Tf"]
        y = 750
        for line in lines:
            safe = (
                str(line)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            content_parts.append("1 0 0 1 50 {0} Tm".format(y))
            content_parts.append("({0}) Tj".format(safe))
            y -= 16
            if y < 50:
                break
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            b"<< /Length " + str(len(content)).encode("ascii") + b" >>\nstream\n"
            + content + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets: List[int] = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(index).encode("ascii")
            pdf += obj
            pdf += b"\nendobj\n"

        xref_pos = len(pdf)
        count = len(objects) + 1
        pdf += b"xref\n"
        pdf += "0 {0}\n".format(count).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += "<< /Size {0} /Root 1 0 R >>\n".format(count).encode("ascii")
        pdf += b"startxref\n"
        pdf += "{0}\n".format(xref_pos).encode("ascii")
        pdf += b"%%EOF\n"
        return bytes(pdf)


# ---------------------------------------------------------------------------
# Orchestration layer
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe facade coordinating users, projects, tasks, messaging,
    performance tracking and reporting."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # Every store shares the SAME lock instance for global consistency.
        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceService(self._lock)
        self.reports = ReportService(self._lock)

    # -- internal helpers --------------------------------------------------
    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    def _require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email) -> None:
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("invalid email address")

    # -- user management ---------------------------------------------------
    def register_user(self, username, email, role: UserRole = UserRole.MEMBER) -> User:
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")
        self._validate_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")

        with self._lock:
            if self.users.username_owner(username) is not None:
                raise DuplicateError("username already in use")
            if self.users.email_owner(email) is not None:
                raise DuplicateError("email already in use")
            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.add(user)
            return self._clone(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [self._clone(u) for u in self.users.all()]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username must be a non-empty string")
                owner = self.users.username_owner(username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already in use")
            if email is not None:
                self._validate_email(email)
                owner = self.users.email_owner(email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already in use")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                self.users.set_username(user, username)
            if email is not None and email != user.email:
                self.users.set_email(user, email)
            if role is not None:
                user.role = role
            return self._clone(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            self._require_user(user_id)
            if self.projects.owned_by(user_id):
                raise ConflictError("user owns one or more projects")
            for task in self.tasks.for_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")
            self.users.remove(user_id)

    # -- project management ------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        if not isinstance(name, str) or not name.strip():
            raise ValidationError("project name must be a non-empty string")
        if end_date < start_date:
            raise ValidationError("end_date must not be before start_date")

        with self._lock:
            self._require_user(owner_id)
            project = Project(
                id=self._next_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
            )
            self.projects.add(project)
            return self._clone(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [self._clone(p) for p in self.projects.all()]

    def update_project(self, project_id, name=None, description=None,
                       start_date=None, end_date=None) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name must be a non-empty string")

            effective_start = start_date if start_date is not None else project.start_date
            effective_end = end_date if end_date is not None else project.end_date
            if effective_end < effective_start:
                raise ValidationError("end_date must not be before start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            return self._clone(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)
            removed_tasks = self.tasks.remove_project(project_id)
            for task in removed_tasks:
                self.messages.remove_for_task(task.id)
            self.messages.remove_for_project(project_id)
            self.projects.remove(project_id)

    # -- task management ---------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        if not isinstance(title, str) or not title.strip():
            raise ValidationError("task title must be a non-empty string")

        with self._lock:
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                assignee_id=assignee_id,
                deadline=deadline,
                status=TaskStatus.NOT_STARTED,
                created_at=self._now(),
            )
            self.tasks.add(task)
            return self._clone(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            return [self._clone(t) for t in self.tasks.for_project(project_id)]

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            self._require_user(assignee_id)
            return [self._clone(t) for t in self.tasks.for_assignee(assignee_id)]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self.tasks.set_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self.tasks.set_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self.tasks.set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline must not be before project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status) -> Task:
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")

        with self._lock:
            task = self._require_task(task_id)
            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return self._clone(task)

    # -- messaging ---------------------------------------------------------
    def post_message(self, author_id, body, project_id=None, task_id=None,
                     parent_id=None, attachments=None) -> Message:
        if (project_id is None) == (task_id is None):
            raise ValidationError("exactly one of project_id or task_id is required")

        with self._lock:
            self._require_user(author_id)
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_objs = self._build_attachments(author_id, attachments)
            if (not isinstance(body, str) or not body.strip()) and not attachment_objs:
                raise ValidationError("message requires a body or an attachment")

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body if isinstance(body, str) else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=self._now(),
                edited_at=None,
            )
            self.messages.add(message)
            return self._clone(message)

    def _build_attachments(self, author_id: int,
                           attachments: Optional[List[Tuple[str, bytes]]]) -> List[Attachment]:
        result: List[Attachment] = []
        if not attachments:
            return result
        now = self._now()
        for item in attachments:
            filename, data = item
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must be non-empty")
            result.append(
                Attachment(
                    filename=filename,
                    size=len(data) if data is not None else 0,
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
            )
        return result

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit the message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must be non-empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data) if data is not None else 0,
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            return [self._clone(m) for m in self.messages.for_project(project_id)]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            return [self._clone(m) for m in self.messages.for_task(task_id)]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete the message")
            self.messages.remove(message_id)

    # -- performance dashboard --------------------------------------------
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate(self.tasks.for_assignee(user_id))

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(self.tasks.for_assignee(user_id))

    @staticmethod
    def _completion_rate(tasks: List[Task]) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    @staticmethod
    def _average_completion_time(tasks: List[Task]) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool) or not 1 <= score <= 5:
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.add_rating(rating)
            return self._clone(rating)

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self.performance.ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self.tasks.for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            ratings = self.performance.ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports -----------------------------------------------------------
    def _user_task_stats(self, user_id: int, project_id: Optional[int] = None) -> dict:
        tasks = self.tasks.for_assignee(user_id)
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        ratings = self.performance.ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": self._completion_rate(tasks),
            "average_completion_time": self._average_completion_time(tasks),
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            self._require_project(project_id)
            tasks = self.tasks.for_project(project_id)
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                stats = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                stats["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    stats["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                user_ids = sorted(
                    {
                        t.assignee_id
                        for t in self.tasks.for_project(project_id)
                        if t.assignee_id is not None
                    }
                )
            else:
                user_ids = [u.id for u in self.users.all()]

            rows = []
            for uid in user_ids:
                user = self.users.get(uid)
                stats = self._user_task_stats(uid, project_id)
                row = {"user_id": uid, "username": user.username if user else ""}
                row.update(stats)
                rows.append(row)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            user = self._require_user(user_id)
            tasks = self.tasks.for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            task_rows = [
                {
                    "id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "assignee_id": t.assignee_id,
                    "deadline": t.deadline.isoformat() if t.deadline else "",
                    "started_at": t.started_at.isoformat() if t.started_at else "",
                    "completed_at": t.completed_at.isoformat() if t.completed_at else "",
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "tasks": task_rows,
            }

    def export_report(self, report, fmt) -> object:
        if not isinstance(report, dict):
            raise ValidationError("report must be a dictionary")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        with self._lock:
            if fmt == ReportFormat.CSV:
                return self.reports.to_csv(report)
            return self.reports.to_pdf(report)


